#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <omp.h>

#ifdef TIMING
#include "timing.h"

struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

#define BLOCK_SIZE 256
#define STR_SIZE 256
#define HALO 1 

void run(int argc, char** argv);

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9
int pyramid_height;

void
init(int argc, char** argv)
{
	if(4 == argc){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
                pyramid_height=atoi(argv[3]);
	}else{
                printf("Usage: dynproc row_len col_len pyramid_height\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; rows > n; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; rows > i; i++)
    {
        for (int j = 0; cols > j; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);

}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void dynproc_kernel(
                int iteration, 
                int *wall,
                int *src,
                int *results,
                int cols, 
                int rows,
                int startStep,
                int border,
                int blockIdx)
{
        int tx;

        int small_block_cols = BLOCK_SIZE-iteration*HALO*2;

        int blkX = small_block_cols*blockIdx-border;
        int blkXmax = blkX+BLOCK_SIZE-1;

        int prev[BLOCK_SIZE];
        int result[BLOCK_SIZE];

        #pragma omp parallel private(tx)
        {
            tx = omp_get_thread_num();
            int validXmin = (0 > blkX) ? -blkX : 0;
            int validXmax = (cols-1 < blkXmax) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

            int W = tx-1;
            int E = tx+1;

            W = (validXmin > W) ? validXmin : W;
            E = (validXmax < E) ? validXmax : E;

            bool isValid = IN_RANGE(tx, validXmin, validXmax);

            int xidx = blkX+tx;

            if(IN_RANGE(xidx, 0, cols-1)){
                prev[tx] = src[xidx];
            }
            #pragma omp barrier
            bool computed = false;
            for (int i=0; iteration > i ; i++){ 
                computed = false;
                if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid){
                    computed = true;
                    int left = prev[W];
                    int up = prev[tx];
                    int right = prev[E];
                    int shortest = MIN(left, up);
                    shortest = MIN(shortest, right);
                    int index = cols*(startStep+i)+xidx;
                    result[tx] = shortest + wall[index];
                }
                #pragma omp barrier
                if(iteration-1 == i)
                    break;
                if(computed)	 
                    prev[tx]= result[tx];
                #pragma omp barrier
            }
            if (computed){
                results[xidx]=result[tx];		
            }
        }
}

int calc_path(int *wall, int *result[2], int rows, int cols, \
	 int pyramid_height, int blockCols, int borderCols)
{
        int src = 1, dst = 0;
	for (int t = 0; rows-1 > t; t+=pyramid_height) {
            int temp = src;
            src = dst;
            dst = temp;
            #pragma omp parallel for
            for (int blockIdx = 0; blockIdx < blockCols; blockIdx++) {
                dynproc_kernel(
                    MIN(pyramid_height, rows-t-1), 
                    wall, result[src], result[dst],
                    cols, rows, t, borderCols, blockIdx);
            }
	}
        return dst;
}

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height)*HALO;
    int smallBlockCol = BLOCK_SIZE-(pyramid_height)*HALO*2;
    int blockCols = cols/smallBlockCol+((0 == cols%smallBlockCol)?0:1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",\
	pyramid_height, cols, borderCols, BLOCK_SIZE, blockCols, smallBlockCol);

    int size = rows*cols;

    int *result_host[2];
    result_host[0] = new int[cols];
    result_host[1] = new int[cols];

    // Initialize result_host[0] with first row of data
    for (int i = 0; i < cols; i++) {
        result_host[0][i] = data[i];
    }

    // wall_host points to data excluding first row
    int *wall_host = data + cols;

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    int final_ret = calc_path(wall_host, result_host, rows, cols, \
	 pyramid_height, blockCols, borderCols);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy final results to result array
    for (int i = 0; i < cols; i++) {
        result[i] = result_host[final_ret][i];
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
            printf("%d ",data[i]) ;
    printf("\n") ;
    for (int i = 0; i < cols; i++)
            printf("%d ",result[i]) ;
    printf("\n") ;
#endif

    delete [] data;
    delete [] wall;
    delete [] result;
    delete [] result_host[0];
    delete [] result_host[1];

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}
